content.text:
 1	.virtual-machine-metrics-tab {
 2	  &__migration-completed-timestamp {
 3	    display: inline;
 4	  }
 5	
 6	  &__main {
 7	    flex-grow: 1;
 8	    display: flex;
 9	    flex-direction: column;
10	    .timerange {
11	      &--main {
12	        display: flex;
13	        justify-content: space-between;
14	        margin: var(--pf-t--global--spacer--sm) var(--pf-t--global--spacer--lg)
15	          var(--pf-t--global--spacer--md) var(--pf-t--global--spacer--lg);
16	        &__text {
17	          font-weight: var(--pf-t--global--font--weight--heading--bold);
18	          display: inline-flex;
19	          align-items: center;
20	          &--time-range {
21	            margin-right: var(--pf-t--global--spacer--200);
22	            width: 100%;
23	          }
24	        }
25	        a {
26	          align-self: center;
27	        }
28	      }
29	    }
30	
31	    .title {
32	      margin: var(--pf-t--global--spacer--400) var(--pf-t--global--spacer--400)
33	        var(--pf-t--global--spacer--200) var(--pf-t--global--spacer--400);
34	    }
35	  }
36	  &__charts {
37	    flex-grow: 1;
38	    .pf-v6-c-card {
39	      margin: var(--pf-t--global--spacer--200);
40	    }
41	    .pf-v6-c-expandable-section__toggle {
42	      align-items: center;
43	      &-text {
44	        font-size: var(--pf-t--global--FontSize--lg);
45	        font-weight: var(--pf-t--global--font--weight--heading--bold);
46	      }
47	    }
48	    .pf-v6-c-expandable-section__content {
49	      margin-top: 0;
50	    }
51	  }
52	}
53	
54	.networkcharts-by-nic--title {
55	  display: inline-flex;
56	}
57	
58	.util-threshold-chart {
59	  width: 100%;
60	  height: 150px;
61	}
62	.network ul.pf-v5-c-dropdown__menu {
63	  max-height: 200px;
64	  overflow-y: scroll;
65	}
66	.network-popover {
67	  display: flex;
68	  justify-content: space-between;
69	}

